function replaceAllExact(input, from, to) {
  if (!input.includes(from)) {
    throw new Error(`Missing expected snippet:\n${from.slice(0, 120)}`);
  }
  return input.split(from).join(to);
}

function applyPairs(input, pairs) {
  return pairs.reduce((acc, [from, to]) => replaceAllExact(acc, from, to), input);
}

